-- Seed MPs from data/members.csv (identity only). Re-runnable (upsert).
on conflict (id) do update set
  name=excluded.name, governorate=excluded.governorate, bloc=excluded.bloc,
  committee=excluded.committee, role=excluded.role, photo=excluded.photo,
  facebook=excluded.facebook, x=excluded.x, instagram=excluded.instagram,
  telegram=excluded.telegram, website=excluded.website;
